  1→{% extends "base.html" %}
  2→
  3→{% block title %}Search - Maimai Assistant{% endblock %}
  4→
  5→{% block content %}
  6→<h2>Search Candidates</h2>
  7→
  8→<form id="search-form">
  9→    <div class="grid">
 10→        <label>
 11→            Keywords (one per line)
 12→            <textarea name="keywords" rows="3" placeholder="e.g. 前端工程师&#10;后端工程师" required></textarea>
 13→        </label>
 14→        <label>
 15→            Company filter (one per line, optional)
 16→            <textarea name="company" rows="3" placeholder="e.g. 字节跳动&#10;快手"></textarea>
 17→        </label>
 18→    </div>
 19→    <div class="grid">
 20→        <label>
 21→            Location (optional)
 22→            <input type="text" name="location" placeholder="e.g. 北京">
 23→        </label>
 24→        <label>
 25→            Pages
 26→            <input type="number" name="pages" value="1" min="1" max="50">
 27→        </label>
 28→    </div>
 29→    <button type="submit">Search</button>
 30→</form>
 31→
 32→<div id="search-progress" hidden>
 33→    <article aria-busy="true">
 34→        <p id="search-progress-text">Searching...</p>
 35→        <progress id="search-progress-bar"></progress>
 36→    </article>
 37→</div>
 38→
 39→<div id="search-results" hidden>
 40→    <h3>Results (<span id="result-count">0</span> candidates)</h3>
 41→    <table>
 42→        <thead>
 43→            <tr>
 44→                <th>#</th>
 45→                <th>Name</th>
 46→                <th>Title</th>
 47→                <th>Company</th>
 48→                <th>Location</th>
 49→            </tr>
 50→        </thead>
 51→        <tbody id="results-body"></tbody>
 52→    </table>
 53→    <button id="export-btn" class="outline" onclick="exportResults()">Export to Excel</button>
 54→</div>
 55→{% endblock %}
 56→
 57→{% block scripts %}
 58→<script>
 59→document.getElementById('search-form').addEventListener('submit', async (e) => {
 60→    e.preventDefault();
 61→    const form = e.target;
 62→    const keywords = form.keywords.value.split('\n').map(s => s.trim()).filter(Boolean);
 63→    const company = form.company.value.split('\n').map(s => s.trim()).filter(Boolean);
 64→    const location = form.location.value.trim() || null;
 65→    const pages = parseInt(form.pages.value) || 1;
 66→
 67→    if (!keywords.length) return alert('Please enter at least one keyword');
 68→
 69→    // Show progress
 70→    document.getElementById('search-progress').hidden = false;
 71→    document.getElementById('search-results').hidden = true;
 72→    form.querySelector('button').disabled = true;
 73→
 74→    try {
 75→        const res = await fetch('/api/search', {
 76→            method: 'POST',
 77→            headers: {'Content-Type': 'application/json'},
 78→            body: JSON.stringify({keywords, company, location, pages}),
 79→        });
 80→        const data = await res.json();
 81→
 82→        // Connect WebSocket for progress
 83→        const ws = connectTaskWS(data.task_id, {
 84→            onEvent(msg) {
 85→                document.getElementById('search-progress-text').textContent =
 86→                    `${msg.event}: ${msg.keyword || ''} ${msg.found ? '(' + msg.found + ' found)' : ''}`;
 87→            },
 88→            onComplete(msg) {
 89→                const candidates = msg.result || [];
 90→                showSearchResults(candidates);
 91→                document.getElementById('search-progress').hidden = true;
 92→                form.querySelector('button').disabled = false;
 93→            },
 94→            onError(msg) {
 95→                alert('Search failed: ' + (msg.error || 'Unknown error'));
 96→                document.getElementById('search-progress').hidden = true;
 97→                form.querySelector('button').disabled = false;
 98→            },
 99→        });
100→    } catch (e) {
101→        alert('Request failed: ' + e.message);
102→        document.getElementById('search-progress').hidden = true;
103→        form.querySelector('button').disabled = false;
104→    }
105→});
106→
107→function showSearchResults(candidates) {
108→    document.getElementById('search-results').hidden = false;
109→    document.getElementById('result-count').textContent = candidates.length;
110→    const tbody = document.getElementById('results-body');
111→    tbody.innerHTML = candidates.map((c, i) => `
112→        <tr>
113→            <td>${i + 1}</td>
114→            <td>${escapeHtml(c.name)}</td>
115→            <td>${escapeHtml(c.title)}</td>
116→            <td>${escapeHtml(c.company)}</td>
117→            <td>${escapeHtml(c.location || '')}</td>
118→        </tr>
119→    `).join('');
120→}
121→
122→async function exportResults() {
123→    const res = await fetch('/api/export', {
124→        method: 'POST',
125→        headers: {'Content-Type': 'application/json'},
126→        body: JSON.stringify({format: 'xlsx'}),
127→    });
128→    const blob = await res.blob();
129→    const url = URL.createObjectURL(blob);
130→    const a = document.createElement('a');
131→    a.href = url;
132→    a.download = 'candidates.xlsx';
133→    a.click();
134→    URL.revokeObjectURL(url);
135→}
136→</script>
137→{% endblock %}
